import React from 'react';
import { Code2, Smartphone, Wrench, Server, Database, Globe } from 'lucide-react';

/**
 * Skills data organized by category
 * Each category has an icon, title, color accent, and a list of skills
 */
const skillsData = [
  {
    category: 'Frontend',
    icon: Code2,
    accent: 'indigo',
    skills: [
      'React',
      'TypeScript',
      'JavaScript (ES6+)',
      'HTML5 / CSS3',
      'Tailwind CSS',
      'Next.js',
      'Redux / Zustand',
      'Responsive Design',
    ],
  },
  {
    category: 'Mobile',
    icon: Smartphone,
    accent: 'emerald',
    skills: [
      'React Native',
      'Kotlin',
      'Android (Jetpack Compose)',
      'Swift / UIKit',
      'Flutter',
      'Cross-platform Development',
    ],
  },
  {
    category: 'Scripting & Tools',
    icon: Wrench,
    accent: 'purple',
    skills: [
      'Python',
      'Node.js',
      'Bash / Shell',
      'Git & GitHub',
      'Docker',
      'CI/CD Pipelines',
      'REST APIs',
      'GraphQL',
    ],
  },
  {
    category: 'Databases',
    icon: Database,
    accent: 'cyan',
    skills: [
      'PostgreSQL',
      'MongoDB',
      'Firebase Firestore',
      'Redis',
      'SQLite',
    ],
  },
  {
    category: 'Backend',
    icon: Server,
    accent: 'orange',
    skills: [
      'Node.js / Express',
      'FastAPI',
      'RESTful Design',
      'Authentication / JWT',
      'WebSocket',
    ],
  },
  {
    category: 'Other',
    icon: Globe,
    accent: 'pink',
    skills: [
      'Agile / Scrum',
      'Technical Writing',
      'Open Source Contribution',
      'Figma / Design Tools',
      'Performance Optimization',
    ],
  },
];

/**
 * Color mapping for each accent type
 * Applied to icons, borders, and text highlights
 */
const accentStyles = {
  indigo: {
    iconBg: 'bg-indigo-500/10',
    iconText: 'text-indigo-400',
    border: 'border-indigo-500/20',
    hoverBorder: 'hover:border-indigo-500/40',
    dot: 'bg-indigo-400',
  },
  emerald: {
    iconBg: 'bg-emerald-500/10',
    iconText: 'text-emerald-400',
    border: 'border-emerald-500/20',
    hoverBorder: 'hover:border-emerald-500/40',
    dot: 'bg-emerald-400',
  },
  purple: {
    iconBg: 'bg-purple-500/10',
    iconText: 'text-purple-400',
    border: 'border-purple-500/20',
    hoverBorder: 'hover:border-purple-500/40',
    dot: 'bg-purple-400',
  },
  cyan: {
    iconBg: 'bg-cyan-500/10',
    iconText: 'text-cyan-400',
    border: 'border-cyan-500/20',
    hoverBorder: 'hover:border-cyan-500/40',
    dot: 'bg-cyan-400',
  },
  orange: {
    iconBg: 'bg-orange-500/10',
    iconText: 'text-orange-400',
    border: 'border-orange-500/20',
    hoverBorder: 'hover:border-orange-500/40',
    dot: 'bg-orange-400',
  },
  pink: {
    iconBg: 'bg-pink-500/10',
    iconText: 'text-pink-400',
    border: 'border-pink-500/20',
    hoverBorder: 'hover:border-pink-500/40',
    dot: 'bg-pink-400',
  },
};

/**
 * SkillCard Component
 * Displays a category card with icon, title, and bulleted skill list
 */
const SkillCard = ({ data, index }) => {
  const styles = accentStyles[data.accent];
  const IconComponent = data.icon;

  return (
    <div
      className={`group bg-slate-900/50 border ${styles.border} ${styles.hoverBorder} rounded-2xl p-6 transition-all duration-300 hover:bg-slate-800/50 hover:shadow-xl hover:-translate-y-1 animate-slide-up`}
      style={{ animationDelay: `${index * 0.08}s` }}
    >
      {/* Category Header */}
      <div className="flex items-center gap-3 mb-5">
        <div className={`p-2.5 rounded-xl ${styles.iconBg}`}>
          <IconComponent size={22} className={styles.iconText} />
        </div>
        <h3 className="text-lg font-semibold text-white">{data.category}</h3>
      </div>

      {/* Skills List */}
      <ul className="space-y-2.5">
        {data.skills.map((skill) => (
          <li key={skill} className="flex items-center gap-2.5 text-sm text-slate-400">
            <span className={`w-1.5 h-1.5 rounded-full ${styles.dot} flex-shrink-0`} />
            {skill}
          </li>
        ))}
      </ul>
    </div>
  );
};

/**
 * Skills Section Component
 * Grid layout displaying categorized technical skills
 */
const Skills = () => {
  return (
    <section id="skills" className="py-24 px-6">
      <div className="max-w-6xl mx-auto">
        {/* Section Header */}
        <div className="text-center mb-14">
          <h2 className="text-3xl sm:text-4xl font-bold text-white mb-4">
            Technical Skills
          </h2>
          <p className="text-slate-400 max-w-xl mx-auto">
            A comprehensive toolkit built through professional experience and personal exploration.
          </p>
        </div>

        {/* Skills Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {skillsData.map((data, index) => (
            <SkillCard key={data.category} data={data} index={index} />
          ))}
        </div>
      </div>
    </section>
  );
};

export default Skills;
